// Structured (outline) form of a rule, for nested-bullet display. `kind`:
//   "priority" — an IF-ladder: ordered `cases` ({value, when?}); last case's
//                 `when` is null (the "otherwise"). `children` carries a lone
//                 condition group for a boolean classification rule.
//   "all"/"any" — AND / OR group over `children` (each itself a RuleNode).
//   "leaf"     — a single clause; `text` is its prose (linkifiable).
export interface RuleNode {
  kind: "priority" | "all" | "any" | "leaf";
  text?: string;
  headline?: string;
  cases?: { value: string; when: RuleNode | null }[];
  children?: RuleNode[] | null;
}

export interface RuleSpeakFieldRule {
  table: string;
  field: string;
  kind: string;        // formula | lookup | rollup | …
  rule: string;        // definitional RuleSpeak sentence (markdown emphasis)
  mechanical: boolean; // true when the wording is faithful but clunky
  refs: RuleSpeakRef[];// fields this rule references (for linkifying the text)
  structure: RuleNode | null; // outline form when the rule is a list; else null
}

